const PROCESSING_FEE = 5;

interface Scenario {
  customer: { yearsWithMHPCO: number };
  steps: Array<{ op: string; items?: unknown[] }>;
}

export const runScenario = (input: unknown): { results: unknown[] } => {
  const scenario = input as Scenario;
  const results = scenario.steps.map((step) => {
    const items = step.items ?? [];
    if (items.length === 0) return { premium: PROCESSING_FEE };
    return { premium: 115 };
  });
  return { results };
};

