const PROCESSING_FEE = 5;
const SWORD_BASE = 100;
const FIRST_INSURANCE_RATE = 0.1;

interface Item {
  type: string;
  material: string;
  enchantment: number;
  cursed: boolean;
}

interface Step {
  op: string;
  items?: Item[];
}

interface Scenario {
  customer: { yearsWithMHPCO: number };
  steps: Step[];
}

const baseValueOf = (_item: Item): number => SWORD_BASE;

const quotePremium = (items: Item[]): number => {
  const baseSum = items.reduce((sum, item) => sum + baseValueOf(item), 0);
  const insuranceSum = baseSum * FIRST_INSURANCE_RATE;
  return baseSum + insuranceSum + PROCESSING_FEE;
};

export const runScenario = (input: unknown): { results: unknown[] } => {
  const scenario = input as Scenario;
  const results = scenario.steps.map((step) => ({
    premium: quotePremium(step.items ?? []),
  }));
  return { results };
};

