const PROCESSING_FEE = 5;
const PLAIN_STEEL_SWORD_PREMIUM = 115;

interface Step {
  op: string;
  items?: unknown[];
}

interface Scenario {
  customer: { yearsWithMHPCO: number };
  steps: Step[];
}

const quotePremium = (items: unknown[]): number =>
  items.length === 0 ? PROCESSING_FEE : PLAIN_STEEL_SWORD_PREMIUM;

export const runScenario = (input: unknown): { results: unknown[] } => {
  const scenario = input as Scenario;
  const results = scenario.steps.map((step) => ({
    premium: quotePremium(step.items ?? []),
  }));
  return { results };
};
